CREATE TABLE "users" ("id" serial PRIMARY KEY, "email" text NOT NULL UNIQUE, "username" text NOT NULL UNIQUE, "name" text, "password_hash" text NOT NULL DEFAULT '', "avatar_url" text, "role" text NOT NULL DEFAULT 'user', "google_id" text UNIQUE, "created_at" text NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" text NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "sessions" ("id" text PRIMARY KEY, "user_id" integer NOT NULL REFERENCES "users"("id"), "expires_at" text NOT NULL, "created_at" text NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "test_results" ("id" serial PRIMARY KEY, "user_id" integer REFERENCES "users"("id"), "wpm" real NOT NULL, "cpm" real NOT NULL, "accuracy" real NOT NULL, "duration" integer NOT NULL, "mode" text NOT NULL DEFAULT 'words', "error_count" integer NOT NULL DEFAULT 0, "char_count" integer NOT NULL DEFAULT 0, "language" text DEFAULT 'english', "created_at" text NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "lessons" ("id" serial PRIMARY KEY, "title" text NOT NULL, "level" text NOT NULL, "category" text NOT NULL, "content" text NOT NULL, "description" text, "order" integer NOT NULL DEFAULT 0, "created_at" text NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "lesson_progress" ("id" serial PRIMARY KEY, "user_id" integer REFERENCES "users"("id"), "lesson_id" integer NOT NULL REFERENCES "lessons"("id"), "wpm" real NOT NULL DEFAULT 0, "accuracy" real NOT NULL DEFAULT 0, "best_wpm" real NOT NULL DEFAULT 0, "completed" boolean NOT NULL DEFAULT false, "completed_at" text, "updated_at" text NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "certificates" ("id" serial PRIMARY KEY, "certificate_id" text NOT NULL UNIQUE, "user_id" integer REFERENCES "users"("id"), "test_result_id" integer REFERENCES "test_results"("id"), "recipient_name" text NOT NULL, "wpm" real NOT NULL, "accuracy" real NOT NULL, "duration" integer NOT NULL, "mode" text NOT NULL, "level" text DEFAULT 'Intermediate', "issued_at" text NOT NULL DEFAULT CURRENT_TIMESTAMP, "created_at" text NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "blog_posts" ("id" serial PRIMARY KEY, "title" text NOT NULL, "slug" text NOT NULL UNIQUE, "content" text NOT NULL, "excerpt" text, "category" text NOT NULL, "cover_image_url" text, "published" boolean NOT NULL DEFAULT false, "author_id" integer REFERENCES "users"("id"), "created_at" text NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" text NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "hr_assessments" ("id" serial PRIMARY KEY, "token" text NOT NULL UNIQUE, "created_by_id" integer NOT NULL REFERENCES "users"("id"), "name" text NOT NULL, "company_name" text NOT NULL, "job_position" text NOT NULL, "description" text, "duration_seconds" integer NOT NULL DEFAULT 300, "difficulty" text NOT NULL DEFAULT 'medium', "language" text NOT NULL DEFAULT 'english', "content_type" text NOT NULL DEFAULT 'words', "custom_text" text, "passing_wpm" integer NOT NULL DEFAULT 40, "min_accuracy" real NOT NULL DEFAULT 90, "max_attempts" integer NOT NULL DEFAULT 1, "active" boolean NOT NULL DEFAULT true, "expires_at" text, "created_at" text NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" text NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "assessment_candidates" ("id" serial PRIMARY KEY, "assessment_id" integer NOT NULL REFERENCES "hr_assessments"("id"), "full_name" text NOT NULL, "email" text NOT NULL, "phone" text, "ip_address" text, "user_agent" text, "fingerprint" text, "tab_switches" integer NOT NULL DEFAULT 0, "attempt_number" integer NOT NULL DEFAULT 1, "started_at" text, "submitted_at" text, "created_at" text NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "assessment_results" ("id" serial PRIMARY KEY, "candidate_id" integer NOT NULL REFERENCES "assessment_candidates"("id"), "assessment_id" integer NOT NULL REFERENCES "hr_assessments"("id"), "wpm" real NOT NULL, "cpm" real NOT NULL, "accuracy" real NOT NULL, "error_count" integer NOT NULL, "char_count" integer NOT NULL, "duration_seconds" integer NOT NULL, "passed" boolean NOT NULL, "rank" integer, "created_at" text NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "follows" ("id" serial PRIMARY KEY, "follower_id" integer NOT NULL REFERENCES "users"("id") ON DELETE CASCADE, "following_id" integer NOT NULL REFERENCES "users"("id") ON DELETE CASCADE, "created_at" text NOT NULL DEFAULT CURRENT_TIMESTAMP, UNIQUE("follower_id", "following_id"));
CREATE TABLE "password_reset_tokens" ("id" serial PRIMARY KEY, "user_id" integer NOT NULL REFERENCES "users"("id") ON DELETE CASCADE, "token" text NOT NULL UNIQUE, "expires_at" text NOT NULL, "used_at" text, "created_at" text NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX "sessions_user_id_idx" ON "sessions" ("user_id");
CREATE INDEX "test_results_user_id_idx" ON "test_results" ("user_id");
CREATE INDEX "test_results_created_at_idx" ON "test_results" ("created_at");
CREATE INDEX "blog_posts_slug_idx" ON "blog_posts" ("slug");
